@app.route('/callback')
def callback():
    config = get_oidc_config()
    
    # Check for error
    if 'error' in request.args:
        return f"Authentication error: {request.args['error']}"
    
    # Get authorization code
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "No authorization code received"
    
    # Exchange code for tokens
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri']
    }
    
    token_response = requests.post(
        config['token_endpoint'],
        data=token_data,
        headers={'Content-Type': 'application/x-www-form-urlencoded'}
    )
    
    if token_response.status_code != 200:
        return "Failed to exchange code for tokens"
    
    token_info = token_response.json()
    
    # Decode ID token
    id_token = token_info.get('id_token')
    if not id_token:
        return "No ID token received"
    
    payload = decode_jwt(id_token)
    if not payload:
        return "Failed to decode ID token"
    
    # Validate nonce
    if not validate_nonce(payload.get('nonce')):
        return "Invalid nonce"
    
    # Validate issuer
    if payload.get('iss') != OIDC_CONFIG['issuer']:
        return "Invalid issuer"
    
    # Validate audience
    if payload.get('aud') != OIDC_CONFIG['client_id']:
        return "Invalid audience"
    
    # Validate expiration
    if payload.get('exp', 0) < time.time():
        return "Token expired"
    
    # Store user info in session
    session['user'] = {
        'sub': payload.get('sub'),
        'name': payload.get('name'),
        'email': payload.get('email'),
        'preferred_username': payload.get('preferred_username')
    }
    
    return redirect(url_for('index'))

